parameters.jsCode:
const data = $input.first().json.output;

// ---------- helpers ----------
const renderList = (items = []) => {
  if (!items.length) return '';
  return (
    '<ul>' +
    items.map(i =>
      '<li><strong>' + i.name + ':</strong> ' + i.value + '</li>'
    ).join('') +
    '</ul>'
  );
};

const renderSimpleList = (items = []) => {
  if (!items.length) return '';
  return (
    '<ul>' +
    items.map(i =>
      '<li>' + i + '</li>'
    ).join('') +
    '</ul>'
  );
};

const renderFeaturesTable = (features = []) => {
  if (!features.length) return '';
  return (
    '<table border=\\"1\\" cellpadding=\\"8\\" cellspacing=\\"0\\" width=\\"100%\\">' +
      '<thead>' +
        '<tr>' +
          '<th align=\\"left\\">Feature</th>' +
          '<th align=\\"left\\">Benefit</th>' +
        '</tr>' +
      '</thead>' +
      '<tbody>' +
        features.map(f =>
          '<tr>' +
            '<td>' + f.name + '</td>' +
            '<td>' + f.value + '</td>' +
          '</tr>'
        ).join('') +
      '</tbody>' +
    '</table>'
  );
};

const renderRealLifeUsage = (usage = []) => {
  if (!usage.length) return '';
  return usage.map(u =>
    '<br><br>' +
    '<strong>' + u.title + '</strong>' +
    '<p>' + u.description + '</p>' +
    '<ul>' +
      u.points.map(p =>
        '<li><strong>' + p.name + ':</strong> ' + p.value + '</li>'
      ).join('') +
    '</ul>'
  ).join('');
};

// ---------- merged content helpers ----------
const renderDecisionFactors = (items = []) =>
  renderList(items.map(i => ({
    name: i.name,
    value: i.why_it_matters + ' ' + i.what_to_prioritize
  })));

const renderUseCaseSegments = (segments = []) =>
  '<ul>' + segments.map(s =>
    '<li><strong>' + s.segment + ':</strong> ' +
    s.description +
    '<ul>' +
      s.top_priorities.map(p =>
        '<li><strong>' + p.name + ':</strong> ' + p.value + '</li>'
      ).join('') +
    '</ul></li>'
  ).join('') + '</ul>';

const renderMistakes = (items = []) =>
  renderList(items.map(i => ({
    name: i.mistake,
    value: i.impact
  })));

const renderObjections = (items = []) =>
  renderList(items.map(i => ({
    name: i.concern,
    value: i.clarification
  })));

// ---------- build HTML ----------
const body_html =
  '<strong>Introduction:</strong>' +
  '<p>' + data.introduction + ' ' + data.buyer_context + '</p>' +

  '<br><br>' +

  '<img src=\\"IMAGE_REPLACE\\" alt=\\"Collection Image\\" style=\\"max-width:100%;height:auto;\\">' +

  '<br><br>' +

  '<strong>' + data.problem_title + '</strong>' +
  '<p>' + data.problem_paragraph + '</p>' +
  renderList(data.problem_pointers) +
  renderMistakes(data.common_mistakes_to_avoid) +

  '<br><br>' +

  '<strong>' + data.solution_title + '</strong>' +
  '<p>' + data.solution_paragraph + '</p>' +
  renderDecisionFactors(data.decision_factors) +
  renderObjections(data.objections_and_clarifications) +

  '<br><br>' +

  '<strong>Key Features &amp; Benefits</strong>' +
  renderFeaturesTable(data.features_and_benefits) +

  '<hr><br>' +

  '<strong>Technical Specifications</strong>' +
  renderList(data.technical_specifications) +
  renderUseCaseSegments(data.use_case_segments) +

  '<hr><br>' +

  renderRealLifeUsage(data.real_life_usage) +

  '<br><br>' +

  '<strong>Selection Checklist</strong>' +
  renderSimpleList(data.selection_checklist) +

  '<br><br>' +

  '<strong>' + data.recommendations_and_cta.title + '</strong>' +
  '<p>' + data.recommendations_and_cta.description + '</p>';

// ---------- return ----------
return [
  {
    json: {
      body_html,
      article_title: data.article_title,
      seo_tags: Array.isArray(data.seo_tags)
        ? data.seo_tags.join(', ')
        : data.seo_tags,
      image_prompt: data.image_generation_prompt
    }
  }
];

